#!/bin/bash
# VoiceFlow SIP Bridge VM Startup Script v5
# Changes from v4:
#  - Installs tcpdump for SIP packet capture
#  - Deploys bridge_v2.js (tcpdump + pure-JS PCAP filter + sipTraceSave integration)

set -e
LOG=/var/log/voiceflow-startup.log
exec >> "$LOG" 2>&1

echo "[$(date)] ── VoiceFlow SIP Bridge startup v5 ──"

# ── System deps ──────────────────────────────────────────────────────────────
apt-get update -qq
apt-get install -y -qq curl gnupg tcpdump

# ── Node.js 20 ───────────────────────────────────────────────────────────────
if ! command -v node &>/dev/null || [[ "$(node -e 'process.stdout.write(process.versions.node.split(".")[0])')" -lt 20 ]]; then
  curl -fsSL https://deb.nodesource.com/setup_20.x | bash -
  apt-get install -y nodejs
fi
echo "[$(date)] Node $(node -v)"

# ── Asterisk ──────────────────────────────────────────────────────────────────
if ! command -v asterisk &>/dev/null; then
  apt-get install -y asterisk
fi

# ── ARI / bridge ─────────────────────────────────────────────────────────────
mkdir -p /opt/voiceflow-bridge
cd /opt/voiceflow-bridge

# Write bridge_v2.js from base64
echo '' | base64 -d > /opt/voiceflow-bridge/bridge.js

# package.json
cat > /opt/voiceflow-bridge/package.json << 'EOF'
{
  "name": "voiceflow-bridge",
  "version": "2.0.0",
  "main": "bridge.js",
  "dependencies": {
    "ari-client": "^2.2.0",
    "axios": "^1.6.0",
    "express": "^4.18.0"
  }
}
EOF

npm install --production --silent

# ── Fetch secrets from GCP Secret Manager ────────────────────────────────────
PROJECT=$(curl -sf "http://metadata.google.internal/computeMetadata/v1/project/project-id" -H "Metadata-Flavor: Google" || echo "voiceflow-ai-202509231639")
get_secret() {
  local name="$1"
  curl -sf "https://secretmanager.googleapis.com/v1/projects/${PROJECT}/secrets/${name}/versions/latest:access" \
    -H "Authorization: Bearer $(curl -sf 'http://metadata.google.internal/computeMetadata/v1/instance/service-accounts/default/token' -H 'Metadata-Flavor: Google' | python3 -c 'import sys,json; print(json.load(sys.stdin)["access_token"])')" \
    | python3 -c 'import sys,json,base64; print(base64.b64decode(json.load(sys.stdin)["payload"]["data"]).decode())' 2>/dev/null || echo ""
}

BRIDGE_SECRET=$(get_secret "BRIDGE_SECRET" || echo "vf_bridge_2024_secure")
FIREBASE_URL="https://us-central1-${PROJECT}.cloudfunctions.net"

# ── Systemd service ───────────────────────────────────────────────────────────
cat > /etc/systemd/system/voiceflow-bridge.service << EOF
[Unit]
Description=VoiceFlow SIP Bridge v2
After=network.target

[Service]
Type=simple
WorkingDirectory=/opt/voiceflow-bridge
ExecStart=/usr/bin/node bridge.js
Restart=always
RestartSec=5
Environment=BRIDGE_SECRET=${BRIDGE_SECRET}
Environment=FIREBASE_URL=${FIREBASE_URL}
Environment=NODE_ENV=production

[Install]
WantedBy=multi-user.target
EOF

systemctl daemon-reload
systemctl enable voiceflow-bridge
systemctl restart voiceflow-bridge

echo "[$(date)] Bridge v2 started (tcpdump SIP capture enabled)"
echo "[$(date)] ── startup v5 complete ──"
